{"command": "cd /tmp/sv-46997f89eccf403a9ff02d62d5392cc9/advanced-multi-complexity && dotnet package list --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build dicts: (project_basename, framework, package_id) -> resolved_version
def build_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                m[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return m

b = build_map(baseline)
a = build_map(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], av))

if changes:
    print('CHANGES:')
    print(f'{\"Project\":<14} {\"Framework\":<8} {\"Package\":<48} {\"Before\":<10} {\"After\":<10}')
    for c in changes:
        print(f'{c[0]:<14} {c[1]:<8} {c[2]:<48} {c[3]:<10} {c[4]:<10}')
else:
    print('No changes detected.')

print()
print(f'Unchanged: {len(unchanged)} package entries')
"
